import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import AuthLayout from '../components/auth/AuthLayout';
import axios from 'axios';

const DEPTS = ['CSE', 'ECE', 'EEE', 'MECH', 'CIVIL', 'IT', 'MBA', 'MCA', 'AIDS', 'AIML', 'CSD'];

export default function SignUp() {
  const [routes, setRoutes] = useState([]);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { register } = useAuth();
  const navigate = useNavigate();

  const [form, setForm] = useState({
    name: '', email: '', password: '', phone: '',
    rollNumber: '', department: '', year: '', section: '',
    address: '', boardingPoint: '', routeId: '', parentName: '', parentPhone: '',
  });

  useEffect(() => {
    axios.get('/routes/public').then(r => setRoutes(r.data)).catch(() => {});
  }, []);

  const setField = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      await register({ ...form, role: 'student' });
      navigate('/student/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <AuthLayout
      subtitle="Student Registration"
      footerLink={{ text: 'Already registered?', to: '/login', label: 'Sign in' }}
    >
      <div style={{ maxHeight: '60vh', overflowY: 'auto', paddingRight: '8px' }}>
        {error && (
          <div className="login-error">
            <span>⚠️</span>
            <span>{error}</span>
          </div>
        )}

        <form onSubmit={handleSubmit} className="animate-fade">
          <div className="form-section-title">Personal Records</div>
          <div className="form-group">
            <label>Full Name</label>
            <input className="input-field" value={form.name} onChange={e => setField('name', e.target.value)} placeholder="As per college ID" required />
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>College Email</label>
              <input className="input-field" type="email" value={form.email} onChange={e => setField('email', e.target.value)} placeholder="rollno@kec.ac.in" required />
            </div>
            <div className="form-group">
              <label>Phone</label>
              <input className="input-field" value={form.phone} onChange={e => setField('phone', e.target.value)} placeholder="10-digit mobile" required />
            </div>
          </div>

          <div className="form-group">
            <label>Create Password</label>
            <input className="input-field" type="password" value={form.password} onChange={e => setField('password', e.target.value)} placeholder="Min. 6 characters" required />
          </div>

          <div className="form-section-title">Academic Details</div>
          <div className="form-row">
            <div className="form-group">
              <label>Roll Number</label>
              <input className="input-field" value={form.rollNumber} onChange={e => setField('rollNumber', e.target.value)} placeholder="e.g. 22CSE01" required />
            </div>
            <div className="form-group">
              <label>Department</label>
              <select className="input-field" value={form.department} onChange={e => setField('department', e.target.value)} required>
                <option value="">Select Dept</option>
                {DEPTS.map(d => <option key={d} value={d}>{d}</option>)}
              </select>
            </div>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Year</label>
              <select className="input-field" value={form.year} onChange={e => setField('year', e.target.value)} required>
                <option value="">Select Year</option>
                {[1, 2, 3, 4].map(y => <option key={y} value={y}>Year {y}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label>Section</label>
              <input className="input-field" value={form.section} onChange={e => setField('section', e.target.value)} placeholder="A / B / C" />
            </div>
          </div>

          <div className="form-section-title">Transport Details</div>
          <div className="form-group">
            <label>Preferred Route</label>
            <select className="input-field" value={form.routeId} onChange={e => setField('routeId', e.target.value)} required>
              <option value="">Select a Bus Route</option>
              {routes.map(r => (
                <option key={r.id} value={r.id}>Route {r.routeNumber} — {r.routeName}</option>
              ))}
            </select>
          </div>
          <div className="form-group">
            <label>Boarding Point</label>
            <input className="input-field" value={form.boardingPoint} onChange={e => setField('boardingPoint', e.target.value)} placeholder="Specific stop location" required />
          </div>

          <div className="form-section-title">Guardian Info</div>
          <div className="form-row">
            <div className="form-group">
              <label>Parent Name</label>
              <input className="input-field" value={form.parentName} onChange={e => setField('parentName', e.target.value)} required />
            </div>
            <div className="form-group">
              <label>Parent Phone</label>
              <input className="input-field" value={form.parentPhone} onChange={e => setField('parentPhone', e.target.value)} required />
            </div>
          </div>

          <button type="submit" className="btn btn-primary login-submit btn-lg" disabled={loading} style={{ margin: '16px 0' }}>
            {loading ? 'Creating Account...' : 'Register for Bus Portal'}
          </button>
        </form>
      </div>
    </AuthLayout>
  );
}
